<?php
namespace app\Services; use app\Repositories\UserRepository; use app\Requests\Validator;
class AuthService{ private UserRepository $users; public function __construct(){ $this->users=new UserRepository(); } public function register(array $d):array{ $e=Validator::required($d,['full_name'=>'Họ tên','email'=>'Email','password'=>'Mật khẩu']); $e+=Validator::email($d,'email','Email'); if(!empty($d['password'])&&strlen($d['password'])<6)$e['password']='Mật khẩu tối thiểu 6 ký tự'; if(!empty($d['email'])&&$this->users->findByEmail($d['email']))$e['email']='Email đã tồn tại'; if($e)return ['ok'=>false,'errors'=>$e]; $id=$this->users->create(['full_name'=>$d['full_name'],'email'=>$d['email'],'phone'=>$d['phone']??null,'student_code'=>$d['student_code']??null,'class_name'=>$d['class_name']??null,'major'=>$d['major']??null,'password'=>password_hash($d['password'],PASSWORD_DEFAULT),'role_id'=>$d['role_id']??2,'status'=>'active']); return ['ok'=>true,'data'=>$this->users->findById($id)]; } public function login(string $email,string $password):array{ $u=$this->users->findByEmail($email); if(!$u||$u['status']!=='active'||!password_verify($password,$u['password'])) return ['ok'=>false,'message'=>'Email hoặc mật khẩu không đúng']; $token=bin2hex(random_bytes(32)); $this->users->updateToken((int)$u['id'],$token); $u=$this->users->findById((int)$u['id']); $u['api_token']=$token; return ['ok'=>true,'data'=>$u]; } public function updateProfile(int $id,array $d):array{ $e=Validator::required($d,['full_name'=>'Họ tên']); if($e)return ['ok'=>false,'errors'=>$e]; $this->users->updateProfile($id,$d); return ['ok'=>true,'data'=>$this->users->findById($id)]; } public function changePassword(int $id,string $old,string $new):array{ $u=$this->users->findById($id); if(!$u||!password_verify($old,$u['password'])) return ['ok'=>false,'message'=>'Mật khẩu hiện tại không đúng']; if(strlen($new)<6)return ['ok'=>false,'message'=>'Mật khẩu mới tối thiểu 6 ký tự']; $this->users->updatePassword($id,password_hash($new,PASSWORD_DEFAULT)); return ['ok'=>true]; }}
